import React from 'react'
import './ThoughtBubble.css'

// Define an array of thought bubbles
const thoughtBubbles = [
    { text: "This is a thought bubble." },
    { text: "I have cats." },
    { text: "This is a CodePen on the internet." },
    { text: "Qui inventore asperiores ipsum asperiores. Ullam voluptas quia quia voluptatem accusantium iste corrupti. Voluptatum deserunt vitae inventore." },
    { text: "This is another thought bubble." },
    { text: "I would walk a thousand miles just to see if you put your name in the Goblet of Fire, Harry." },
    { text: "&#x1f192;" }
];

// Example function to display the thoughts
function displayThoughts() {
    thoughtBubbles.forEach(bubble => {
        console.log(bubble.text);
    });
}

const ThoughtBubble = () => {
    return (
      <div>
        displayThoughts();
      </div>
    )
  }

export default ThoughtBubbles;
